import numpy as np

class QueryRouter:
    def __init__(self, domains, model, threshold=-1.0):
        self.domains = domains
        self.model = model
        self.threshold = threshold

    def route(self, query):
        names = list(self.domains.keys())
        descs = list(self.domains.values())
        scores = self.model.predict([[query, d] for d in descs])
        best_idx = int(np.argmax(scores))
        best_score = float(scores[best_idx])

        if best_score < self.threshold:
            return {"domain": "out_of_scope", "score": best_score}
        return {"domain": names[best_idx], "score": best_score}

    def route_multi(self, query, gap_threshold=2.0):
        names = list(self.domains.keys())
        descs = list(self.domains.values())
        scores = self.model.predict([[query, d] for d in descs])
        order = np.argsort(scores)[::-1]

        top = float(scores[order[0]])
        second = float(scores[order[1]]) if len(order) > 1 else float('-inf')

        if top - second < gap_threshold:
            return {"domains": [names[order[0]], names[order[1]]], "ambiguous": True}
        return {"domains": [names[order[0]]], "ambiguous": False}

