class RoutedRAGPipeline:
    def __init__(self, router, retrievers):
        self.router = router
        self.retrievers = retrievers

    def answer(self, query, llm_fn, top_k=3):
        route = self.router.route(query)

        if route["domain"] == "out_of_scope":
            return {"answer": "I can't help with that topic.",
                    "domain": "out_of_scope", "confidence": route["score"]}

        retriever = self.retrievers[route["domain"]]
        docs = retriever.search(query, top_k=top_k)
        context = "\n".join(f"- {d}" for d in docs)

        prompt = f"Context:\n{context}\n\nQuestion: {query}\nAnswer:"
        answer = llm_fn(prompt)

        return {"answer": answer, "domain": route["domain"],
                "confidence": route["score"], "sources": docs}

# Integration pattern for Homie
def build_homie_pipeline(cross_encoder, domain_config, retrievers):
    router = QueryRouter(domain_config, cross_encoder, threshold=-1.0)
    return RoutedRAGPipeline(router, retrievers)
